      "issue": "离子色谱法测定硝酸盐结果以硝酸根离子（NO3⁻）计，但检出限0.08 mg/L通常对应以氮（N）计的标准，两者单位不一致或数值量级存疑。"
    },
    {
      "section": "③",
      "issue": "训练集130组加测试集31组共161组，与总样本量153组数据自相矛盾。"
    },
    {
      "section": "④",
      "issue": "总样本量153组，分两组（78和75）进行独立样本t检验，自由度应为151，文中df=120缺乏依据且与样本量不符。"
    },
    {
      "section": "⑥",
      "issue": "将硝酸盐标准限值10 mg/L（以N

[
  {"节": "③", "缺陷": "训练集与测试集样本数之和（161）与第①节总样本数（153）自相矛盾"},
  {"节": "④", "缺陷": "独立样本t检验的自由度应为两组样本量之和减2（即151），而非120"},
  {"节": "⑥", "缺陷": "测定值以NO3⁻计而限值以N计，直接比较未换算单位导致超标判定错误"}
]

[
  {
    "节": "⑥",
    "缺陷": "插值结果范围(3-15 mg/kg)与实测数据范围(0.05-0.83 mg/kg)严重矛盾，违背克里金插值不产生极值的基本性质。"
  }
]

[
  {
    "节": "⑥",
    "缺陷": "插值预测值（3-15 mg/kg）严重超出实际实测范围（0.05-0.83 mg/kg），存在量级矛盾且疑似未使用实测数据进行验证或插值方法有误。"
  }
]

[
  {
    "节": "①",
    "缺陷": "样点总数计算错误（96+57=153与正文一致，但通常此类研究需检查样本量与后续统计检验的匹配性，此处数值无误，但结合④发现每折30个样点*10折=300个样点，与153个样本严重矛盾）"
  },
  {
    "节": "④",
    "缺陷": "十折交叉验证总样本量计算错误（每折30个样点×10折=300个，与①中总样点数153个严重矛盾）"
  },
  {
    "节": "⑥",
    "缺陷": "插值预测范围与实测范围严重矛盾（⑤中Cd实测最高0.83 mg/kg，⑥中克里金插值预测值高达3–15 mg/kg，超出实测数据范围且无异常值说明，属统计外推硬伤）"
  }
]

[
  {"节": "③", "缺陷": "模型以重金属实测浓度作为输入特征去预测由其直接计算得出的综合风险指数，属于循环论证且丧失预测意义"},
  {"节": "④", "缺陷": "153个样点划分十折交叉验证每折仅约15个样本，文中“每折约30个样点”与总样本数存在明显计算矛盾"},
  {"节": "⑥", "缺陷": "克里金插值预测的Cd含量范围（3–15 mg/kg）与实测范围（0.05–0.83 mg/kg）严重背离，违背空间插值不超越数据极值的基本原理"}
]

[
  {"节": "③", "缺陷": "训练集130组与测试集31组合计161组，与①中总样本数153组矛盾，划分数量不自洽。"},
  {"节": "④", "缺陷": "①中两期样本为78、75，独立样本t检验自由度应约为151，给出df=120与样本量不一致。"},
  {"节": "⑥", "缺陷": "②中测定值以NO3⁻计，却直接与以N计的10 mg/L限值比较，未做N/NO3⁻换算，超标率错误。"}
]

